 21	class SeededRng implements Rng {
 22	  #state: number;
 23	
 24	  constructor(private readonly streamKey: string) {
 25	    this.#state = hashStringToUint32(streamKey);
 26	  }
 27	
 28	  nextUint32(): number {
 29	    this.#state = (this.#state + 0x6d2b_79f5) >>> 0;
 30	
 31	    let value = this.#state;
 32	    value = Math.imul(value ^ (value >>> 15), value | 1);
 33	    value ^= value + Math.imul(value ^ (value >>> 7), value | 61);
 34	
 35	    return (value ^ (value >>> 14)) >>> 0;
 36	  }
 37	
 38	  fork(label: string): Rng {
 39	    return new SeededRng(streamKeyForFork(this.streamKey, label));
 40	  }
 41	
 42	  int(min: number, max: number): number {
 43	    assertSafeInteger(min, "min");
 44	    assertSafeInteger(max, "max");
 45	
 46	    if (min > max) {
 47	      throw new RangeError("min must be less than or equal to max");
 48	    }
 49	
 50	    const range = max - min + 1;
 51	    if (range < 1 || range > UINT32_SIZE) {
 52	      throw new RangeError("range must contain between 1 and 4294967296 values");
 53	    }
 54	
 55	    const limit = UINT32_SIZE - (UINT32_SIZE % range);
 56	    let value = this.nextUint32();
 57	
 58	    while (value >= limit) {
 59	      value = this.nextUint32();
 60	    }
 61	
 62	    return min + (value % range);
 63	  }
