 65	  pick<T>(items: readonly T[]): T {
 66	    assertNonEmpty(items, "items");
 67	    return getAt(items, this.int(0, items.length - 1));
 68	  }
 69	
 70	  weightedPick<T>(items: readonly T[], weights: readonly number[]): T {
 71	    assertNonEmpty(items, "items");
 72	
 73	    if (items.length !== weights.length) {
 74	      throw new RangeError("items and weights must have the same length");
 75	    }
 76	
 77	    let total = 0;
 78	    for (const weight of weights) {
 79	      assertSafeInteger(weight, "weight");
 80	
 81	      if (weight < 0) {
 82	        throw new RangeError("weights must be greater than or equal to 0");
 83	      }
 84	
 85	      total += weight;
 86	      if (total > UINT32_MAX) {
 87	        throw new RangeError("total weight must be less than or equal to 4294967295");
 88	      }
 89	    }
 90	
 91	    if (total === 0) {
 92	      throw new RangeError("at least one weight must be greater than 0");
 93	    }
 94	
 95	    const roll = this.int(1, total);
 96	    let runningTotal = 0;
 97	
 98	    for (let index = 0; index < weights.length; index += 1) {
 99	      runningTotal += getAt(weights, index);
100	      if (roll <= runningTotal) {
101	        return getAt(items, index);
102	      }
103	    }
104	
105	    throw new Error("weighted pick failed to select an item");
106	  }
