108	  shuffle<T>(items: readonly T[]): T[] {
109	    const shuffled = [...items];
110	
111	    for (let index = shuffled.length - 1; index > 0; index -= 1) {
112	      const swapIndex = this.int(0, index);
113	      const value = getAt(shuffled, index);
114	      shuffled[index] = getAt(shuffled, swapIndex);
115	      shuffled[swapIndex] = value;
116	    }
