132	function hashStringToUint32(value: string): number {
133	  let hash = FNV_OFFSET_BASIS;
134	
135	  for (let index = 0; index < value.length; index += 1) {
136	    hash ^= value.charCodeAt(index);
137	    hash = Math.imul(hash, FNV_PRIME) >>> 0;
138	  }
139	
140	  return hash >>> 0;
141	}
